use std::sync::Arc;
use anyhow::Result;
use async_trait::async_trait;

/// Error type for integration operations
#[derive(Debug, thiserror::Error)]
pub enum IntegrationError {
    #[error("External service unavailable: {0}")]
    ServiceUnavailable(String),

    #[error("Translation failed: {0}")]
    TranslationFailed(String),

    #[error("External entity not found: {0}")]
    NotFound(String),

    #[error("Integration error: {0}")]
    Other(#[from] anyhow::Error),
}

/// Trait for module adapters
///
/// Implement this trait to adapt external module types to internal domain.
#[async_trait]
pub trait ModuleAdapter: Send + Sync {
    /// External type from the other module
    type External;
    /// Internal type in this module's domain
    type Internal;

    /// Translate external type to internal type
    fn to_internal(&self, external: Self::External) -> Result<Self::Internal, IntegrationError>;

    /// Translate internal type to external type (for publishing)
    fn to_external(&self, internal: Self::Internal) -> Result<Self::External, IntegrationError>;
}

/// Trait for module facades
///
/// Facades provide simplified access to external module functionality.
#[async_trait]
pub trait ModuleFacade: Send + Sync {
    /// Check if the external module is available
    async fn is_available(&self) -> bool;

    /// Get the module name
    fn module_name(&self) -> &'static str;
}

