/// Registry for external module integrations
///
/// Use this to register and retrieve adapters for external modules.
pub struct IntegrationRegistry {
    adapters: std::collections::HashMap<String, Arc<dyn std::any::Any + Send + Sync>>,
}

impl IntegrationRegistry {
    /// Create a new empty registry
    pub fn new() -> Self {
        Self {
            adapters: std::collections::HashMap::new(),
        }
    }

    /// Register an adapter for a module
    pub fn register<T: Send + Sync + 'static>(&mut self, module_name: &str, adapter: Arc<T>) {
        self.adapters.insert(module_name.to_string(), adapter);
    }

    /// Get an adapter for a module
    pub fn get<T: Send + Sync + 'static>(&self, module_name: &str) -> Option<Arc<T>> {
        self.adapters
            .get(module_name)
            .and_then(|a| Arc::clone(a).downcast::<T>().ok())
    }

    /// Check if a module adapter is registered
    pub fn has(&self, module_name: &str) -> bool {
        self.adapters.contains_key(module_name)
    }
}

impl Default for IntegrationRegistry {
    fn default() -> Self {
        Self::new()
    }
}

